export function getCourse(slug: string) { return COURSES.find((course) => course.slug === slug); }
export function getLesson(course: Course, slug: string) {
  for (const courseModule of course.modules) {
    const lesson = courseModule.lessons.find((item) => item.slug === slug);
    if (lesson) return { lesson, module: courseModule };
  }
}
export function getCourseLessons(course: Course) { return course.modules.flatMap((module) => module.lessons); }
export function getCitation(id: string) { return CITATIONS.find((citation) => citation.id === id); }
